const PF2E_DC_BY_LEVEL = [12,13,14,16,17,18,20,21,22,24,25,26,28,29,30,32,33,34,36,37,38,40,42,44,46,48];
const DEFAULT_PARTICIPANT_NAME = "Р В Р’В Р В РІвЂљВ¬Р В Р Р‹Р Р†Р вЂљР Р‹Р В Р’В Р вЂ™Р’В°Р В Р Р‹Р В РЎвЂњР В Р Р‹Р Р†Р вЂљРЎв„ўР В Р’В Р В РІР‚В¦Р В Р’В Р РЋРІР‚ВР В Р’В Р РЋРІР‚Сњ";
const DEFAULT_PARTICIPANT_IMG = "icons/svg/mystery-man.svg";
const OWNER_PERMISSION_LEVEL = CONST?.DOCUMENT_OWNERSHIP_LEVELS?.OWNER ?? 3;

function resolveParticipantActor(participant) {
    if (!participant) return null;

    for (const uuid of [participant.uuid, participant.actorUuid]) {
        if (!uuid) continue;
        try {
            const resolved = typeof fromUuidSync === "function" ? fromUuidSync(uuid) : null;
            const actor = resolved?.actor ?? resolved ?? null;
            if (actor?.system) return actor;
        } catch (_err) {}
    }

    if (participant.id) {
        const actor = game.actors.get(participant.id);
        if (actor) return actor;
    }

    const token = canvas.tokens?.placeables?.find((placeable) => {
        const actor = placeable.actor;
        return actor?.id === participant.id || actor?.uuid === participant.uuid || placeable.document?.uuid === participant.uuid;
    });
    return token?.actor ?? null;
}

function getParticipantName(participant, actor = resolveParticipantActor(participant)) {
    return actor?.name || participant?.name || DEFAULT_PARTICIPANT_NAME;
}

function getParticipantShortName(participant, actor = resolveParticipantActor(participant)) {
    return getParticipantName(participant, actor).split(/\s+/).filter(Boolean)[0] || DEFAULT_PARTICIPANT_NAME;
}

function getParticipantImage(participant, actor = resolveParticipantActor(participant)) {
    return actor?.img || participant?.img || DEFAULT_PARTICIPANT_IMG;
}

function getParticipantLevel(participant, actor = resolveParticipantActor(participant)) {
    return actor?.level || actor?.system?.details?.level?.value || participant?.level || 0;
}

function getParticipantType(participant, actor = resolveParticipantActor(participant)) {
    return actor?.type || participant?.actorType || "";
}

function isParticipantOwner(participant, actor = resolveParticipantActor(participant)) {
    if (!actor) return false;
    try {
        return actor.testUserPermission?.(game.user, OWNER_PERMISSION_LEVEL) ?? !!actor.isOwner;
    } catch (_err) {
        return !!actor.isOwner;
    }
}

function syncParticipantSnapshot(participant, actor = resolveParticipantActor(participant)) {
    if (!participant) return { actor: null, name: DEFAULT_PARTICIPANT_NAME, img: DEFAULT_PARTICIPANT_IMG, type: "", level: 0 };

    const name = getParticipantName(participant, actor);
    const img = getParticipantImage(participant, actor);
    const type = getParticipantType(participant, actor);
    const level = getParticipantLevel(participant, actor);

    participant.name = name;
    participant.img = img;
    participant.actorType = type;
    participant.level = level;
    if (actor?.uuid) participant.uuid = actor.uuid;

    return { actor, name, img, type, level };
}

function hasComplaintFrom(participant, byId, byName) {
    const complaints = participant?.complaints || [];
    return (byId && complaints.includes(byId)) || (byName && complaints.includes(byName));
}

function normalizeDiceValues(values, fallback = []) {
    const source = Array.isArray(values) ? values : fallback;
    return source.map((value) => {
        const numeric = Number(value);
        return Number.isFinite(numeric) ? numeric : null;
    });
}

function toSafeNumber(value, fallback = 0) {
    const numeric = Number(value);
    return Number.isFinite(numeric) ? numeric : fallback;
}

function formatModifier(value, { forceSign = false } = {}) {
    const numeric = toSafeNumber(value, 0);
    if (numeric > 0 && forceSign) return `+${numeric}`;
    if (numeric < 0) return `${numeric}`;
    return forceSign ? "+0" : "0";
}

function getHandPresentation(playerDice, centerDice) {
    const result = evaluateHand(playerDice, centerDice);
    const dice = [...normalizeDiceValues(playerDice), ...normalizeDiceValues(centerDice)]
        .filter((value) => Number.isFinite(value) && value > 0)
        .sort((a, b) => a - b);

    const counts = {};
    for (const value of dice) counts[value] = (counts[value] || 0) + 1;
    const freqs = Object.entries(counts)
        .map(([value, count]) => ({ value: Number(value), count }))
        .sort((a, b) => b.count - a.count || b.value - a.value);

    let highlightedValues = [];
    if (freqs.length) {
        if (result.name === "Р В Р’В Р РЋРІвЂћСћР В Р’В Р В РІвЂљВ¬Р В Р’В Р Р†Р вЂљР’ВР В Р’В Р РЋРІР‚С”Р В Р’В Р РЋРІвЂћСћР В Р’В Р Р†Р вЂљРЎС›Р В Р’В Р вЂ™Р’В " || result.name === "Р В Р’В Р РЋРІвЂћСћР В Р’В Р вЂ™Р’В°Р В Р Р‹Р В РІР‚С™Р В Р’В Р вЂ™Р’Вµ" || result.name === "Р В Р’В Р В Р вЂ№Р В Р’В Р вЂ™Р’ВµР В Р Р‹Р Р†Р вЂљРЎв„ў" || result.name === "Р В Р’В Р РЋРЎСџР В Р’В Р вЂ™Р’В°Р В Р Р‹Р В РІР‚С™Р В Р’В Р вЂ™Р’В°") {
            highlightedValues = [freqs[0].value];
        } else if (result.name === "Р В Р’В Р вЂ™Р’В¤Р В Р Р‹Р РЋРІР‚СљР В Р’В Р вЂ™Р’В»Р В Р’В Р вЂ™Р’В»-Р В Р’В Р СћРЎвЂ™Р В Р’В Р вЂ™Р’В°Р В Р Р‹Р РЋРІР‚СљР В Р Р‹Р В РЎвЂњ" || result.name === "Р В Р’В Р Р†Р вЂљРЎСљР В Р’В Р В РІР‚В Р В Р’В Р вЂ™Р’Вµ Р В Р’В Р РЋРІР‚вЂќР В Р’В Р вЂ™Р’В°Р В Р Р‹Р В РІР‚С™Р В Р Р‹Р Р†Р вЂљРІвЂћвЂ“") {
            highlightedValues = freqs.slice(0, 2).map((entry) => entry.value);
        } else if (result.name === "Р В Р’В Р В Р вЂ№Р В Р Р‹Р Р†Р вЂљРЎв„ўР В Р Р‹Р В РІР‚С™Р В Р’В Р РЋРІР‚ВР В Р Р‹Р Р†Р вЂљРЎв„ў") {
            highlightedValues = [...new Set(dice)];
        } else if (dice.length) {
            highlightedValues = [Math.max(...dice)];
        }
    }

    return {
        ...result,
        displayDice: dice.map((value) => ({ value, isCombo: highlightedValues.includes(value) }))
    };
}

function renderMiniDiceRow(dice, extraClass = "") {
    if (!Array.isArray(dice) || !dice.length) return "";
    return `<div class="kb-mini-dice-row ${extraClass}">${dice.map((die) => `<div class="kb-mini-die ${die.isCombo ? "combo" : ""}">${die.value}</div>`).join("")}</div>`;
}

// === 2. Р В Р’В Р вЂ™Р’В Р В Р вЂ Р В РІР‚С™Р Р†РІР‚С›РЎС›Р В Р’В Р вЂ™Р’В Р В Р’В Р В РІР‚в„–Р В Р’В Р вЂ™Р’В Р В Р Р‹Р РЋРЎСџР В Р’В Р вЂ™Р’В Р В Р Р‹Р Р†Р вЂљРЎвЂќР В Р’В Р вЂ™Р’В Р В Р Р‹Р РЋРІвЂћСћР В Р’В Р вЂ™Р’В Р В Р Р‹Р Р†Р вЂљРЎвЂќР В Р’В Р вЂ™Р’В Р В Р вЂ Р В РІР‚С™Р РЋРЎв„ўР В Р’В Р вЂ™Р’В Р В Р Р‹Р Р†Р вЂљРІвЂћСћР В Р’В Р вЂ™Р’В Р В Р Р‹Р РЋРІР‚С”Р В Р’В Р вЂ™Р’В Р В Р вЂ Р В РІР‚С™Р РЋРЎвЂєР В Р’В Р вЂ™Р’В Р В Р вЂ Р В РІР‚С™Р РЋРІР‚СњР В Р’В Р вЂ™Р’В Р В РІР‚в„ўР вЂ™Р’В¬Р В Р’В Р вЂ™Р’В Р В Р Р‹Р РЋРЎв„ўР В Р’В Р вЂ™Р’В Р В РІР‚в„ўР вЂ™Р’В«Р В Р’В Р вЂ™Р’В Р В Р вЂ Р В РІР‚С™Р РЋРЎвЂє Р В Р’В Р вЂ™Р’В Р В РІР‚в„ўР вЂ™Р’В¤Р В Р’В Р вЂ™Р’В Р В Р’В Р Р†РІР‚С™Р’В¬Р В Р’В Р вЂ™Р’В Р В Р Р‹Р РЋРЎв„ўР В Р’В Р вЂ™Р’В Р В Р Р‹Р Р†РІР‚С›РЎС›Р В Р’В Р вЂ™Р’В Р В РІР‚в„ўР вЂ™Р’В¦Р В Р’В Р вЂ™Р’В Р В РІР‚в„ўР вЂ™Р’ВР В Р’В Р вЂ™Р’В Р В РІР‚в„ўР вЂ™Р’В ===
function getActorMods(actor) {
    if (!actor) return { soc: 0, dip: 0, thi: 0, dec: 0, per: 0, itm: 0, lore: 0 };
    const isNPC = actor.type === "npc";
    const sys = actor.system;
    const level = sys.details?.level?.value || 0;
    const intMod = sys.abilities?.int?.mod || 0;
    const getVal = (slug) => {
        if (slug === 'perception') return isNPC ? (sys.perception?.mod || 0) : (actor.perception?.mod || 0);
        return isNPC ? (sys.skills?.[slug]?.base || sys.skills?.[slug]?.value || 0) : (actor.skills?.[slug]?.mod || 0);
    };
    const loreItem = actor.items.find(i => i.type === "lore" && (i.name.toLowerCase().includes('game') || i.name.toLowerCase().includes('Р В Р’В Р вЂ™Р’В Р В Р Р‹Р Р†Р вЂљР’ВР В Р’В Р вЂ™Р’В Р В Р Р‹Р Р†Р вЂљРІР‚СљР В Р’В Р В Р вЂ№Р В Р’В Р Р†Р вЂљРЎв„ўР В Р’В Р вЂ™Р’В Р В РІР‚в„ўР вЂ™Р’В°')));
    let loreMod = intMod;
    if (loreItem) {
        if (isNPC) loreMod = loreItem.system.mod?.value || intMod;
        else {
            const rank = loreItem.system.proficient?.value || 0;
            loreMod = rank > 0 ? (rank * 2 + level + intMod) : intMod;
        }
    }
    return { soc: getVal('society'), dip: getVal('diplomacy'), thi: getVal('thievery'), dec: getVal('deception'), per: getVal('perception'), itm: getVal('intimidation'), lore: loreMod };
}

function evaluateHand(playerDice, centerDice) {
    let dice = [...normalizeDiceValues(playerDice), ...normalizeDiceValues(centerDice)].filter(d => d > 0).sort((a,b) => b-a);
    if (dice.length < 2) return { name: "Р В Р’В Р вЂ™Р’В Р В Р Р‹Р РЋРЎв„ўР В Р’В Р вЂ™Р’В Р В Р Р‹Р Р†Р вЂљР’ВР В Р’В Р В Р вЂ№Р В Р вЂ Р В РІР‚С™Р В Р вЂ№Р В Р’В Р вЂ™Р’В Р В РІР‚в„ўР вЂ™Р’ВµР В Р’В Р вЂ™Р’В Р В Р Р‹Р Р†Р вЂљРІР‚СљР В Р’В Р вЂ™Р’В Р В Р Р‹Р Р†Р вЂљРЎС›", score: 0 };
    let counts = {}; dice.forEach(d => counts[d] = (counts[d] || 0) + 1);
    let freqs = Object.entries(counts).map(([v, c]) => ({val: parseInt(v), count: c})).sort((a,b) => b.count - a.count || b.val - a.val);
    let isStraight = (new Set(dice).size === 5) && (dice[0] - dice[4] === 4);
    let rank = 1, name = "Р В Р’В Р вЂ™Р’В Р В Р’В Р В РІР‚в„–Р В Р’В Р В Р вЂ№Р В Р вЂ Р В РІР‚С™Р РЋРІвЂћСћР В Р’В Р вЂ™Р’В Р В РІР‚в„ўР вЂ™Р’В°Р В Р’В Р В Р вЂ№Р В Р’В Р Р†Р вЂљРЎв„ўР В Р’В Р В Р вЂ№Р В Р вЂ Р Р†Р вЂљРЎв„ўР вЂ™Р’В¬Р В Р’В Р вЂ™Р’В Р В РІР‚в„ўР вЂ™Р’В°Р В Р’В Р В Р вЂ№Р В Р’В Р В Р РЏ Р В Р’В Р вЂ™Р’В Р В Р Р‹Р Р†Р вЂљРЎСљР В Р’В Р вЂ™Р’В Р В Р Р‹Р Р†Р вЂљРЎС›Р В Р’В Р В Р вЂ№Р В Р’В Р РЋРІР‚СљР В Р’В Р В Р вЂ№Р В Р вЂ Р В РІР‚С™Р РЋРІвЂћСћР В Р’В Р В Р вЂ№Р В Р’В Р В РІР‚В°";
    if (freqs[0].count === 5) { rank = 8; name = "Р В Р’В Р вЂ™Р’В Р В Р Р‹Р Р†РІР‚С›РЎС›Р В Р’В Р вЂ™Р’В Р В Р’В Р Р†РІР‚С™Р’В¬Р В Р’В Р вЂ™Р’В Р В Р вЂ Р В РІР‚С™Р вЂ™Р’ВР В Р’В Р вЂ™Р’В Р В Р Р‹Р Р†Р вЂљРЎвЂќР В Р’В Р вЂ™Р’В Р В Р Р‹Р Р†РІР‚С›РЎС›Р В Р’В Р вЂ™Р’В Р В Р вЂ Р В РІР‚С™Р РЋРЎвЂєР В Р’В Р вЂ™Р’В Р В РІР‚в„ўР вЂ™Р’В "; }
    else if (freqs[0].count === 4) { rank = 7; name = "Р В Р’В Р вЂ™Р’В Р В Р Р‹Р Р†РІР‚С›РЎС›Р В Р’В Р вЂ™Р’В Р В РІР‚в„ўР вЂ™Р’В°Р В Р’В Р В Р вЂ№Р В Р’В Р Р†Р вЂљРЎв„ўР В Р’В Р вЂ™Р’В Р В РІР‚в„ўР вЂ™Р’Вµ"; }
    else if (freqs[0].count === 3 && freqs[1].count === 2) { rank = 6; name = "Р В Р’В Р вЂ™Р’В Р В РІР‚в„ўР вЂ™Р’В¤Р В Р’В Р В Р вЂ№Р В Р Р‹Р Р†Р вЂљРЎС™Р В Р’В Р вЂ™Р’В Р В РІР‚в„ўР вЂ™Р’В»Р В Р’В Р вЂ™Р’В Р В РІР‚в„ўР вЂ™Р’В»-Р В Р’В Р вЂ™Р’В Р В РЎС›Р РЋРІР‚в„ўР В Р’В Р вЂ™Р’В Р В РІР‚в„ўР вЂ™Р’В°Р В Р’В Р В Р вЂ№Р В Р Р‹Р Р†Р вЂљРЎС™Р В Р’В Р В Р вЂ№Р В Р’В Р РЋРІР‚Сљ"; }
    else if (isStraight) { rank = 5; name = "Р В Р’В Р вЂ™Р’В Р В Р’В Р В РІР‚в„–Р В Р’В Р В Р вЂ№Р В Р вЂ Р В РІР‚С™Р РЋРІвЂћСћР В Р’В Р В Р вЂ№Р В Р’В Р Р†Р вЂљРЎв„ўР В Р’В Р вЂ™Р’В Р В Р Р‹Р Р†Р вЂљР’ВР В Р’В Р В Р вЂ№Р В Р вЂ Р В РІР‚С™Р РЋРІвЂћСћ"; }
    else if (freqs[0].count === 3) { rank = 4; name = "Р В Р’В Р вЂ™Р’В Р В Р’В Р В РІР‚в„–Р В Р’В Р вЂ™Р’В Р В РІР‚в„ўР вЂ™Р’ВµР В Р’В Р В Р вЂ№Р В Р вЂ Р В РІР‚С™Р РЋРІвЂћСћ"; }
    else if (freqs[0].count === 2 && freqs[1].count === 2) { rank = 3; name = "Р В Р’В Р вЂ™Р’В Р В Р вЂ Р В РІР‚С™Р РЋРЎС™Р В Р’В Р вЂ™Р’В Р В Р’В Р Р†Р вЂљР’В Р В Р’В Р вЂ™Р’В Р В РІР‚в„ўР вЂ™Р’Вµ Р В Р’В Р вЂ™Р’В Р В Р Р‹Р Р†Р вЂљРІР‚СњР В Р’В Р вЂ™Р’В Р В РІР‚в„ўР вЂ™Р’В°Р В Р’В Р В Р вЂ№Р В Р’В Р Р†Р вЂљРЎв„ўР В Р’В Р В Р вЂ№Р В Р вЂ Р В РІР‚С™Р Р†РІР‚С›РІР‚вЂњ"; }
    else if (freqs[0].count === 2) { rank = 2; name = "Р В Р’В Р вЂ™Р’В Р В Р Р‹Р РЋРЎСџР В Р’В Р вЂ™Р’В Р В РІР‚в„ўР вЂ™Р’В°Р В Р’В Р В Р вЂ№Р В Р’В Р Р†Р вЂљРЎв„ўР В Р’В Р вЂ™Р’В Р В РІР‚в„ўР вЂ™Р’В°"; }
    let score = rank * 100000000;
    let mult = 1000000;
    for (let f of freqs) { for (let i=0; i<f.count; i++) { score += f.val * mult; mult /= 100; } }
    return { name, score };
}

// === 3. Р В Р’В Р вЂ™Р’В Р В Р’В Р Р†Р вЂљР Р‹Р В Р’В Р вЂ™Р’В Р В Р вЂ Р В РІР‚С™Р РЋРЎС™Р В Р’В Р вЂ™Р’В Р В РІР‚в„ўР вЂ™Р’В Р В Р’В Р вЂ™Р’В Р В Р Р‹Р Р†Р вЂљРЎвЂќ Р В Р’В Р вЂ™Р’В Р В Р Р‹Р Р†Р вЂљРЎвЂќР В Р’В Р вЂ™Р’В Р В Р вЂ Р В РІР‚С™Р вЂ™Р’ВР В Р’В Р вЂ™Р’В Р В РІР‚в„ўР вЂ™Р’В Р В Р’В Р вЂ™Р’В Р В Р Р‹Р Р†Р вЂљРІвЂћСћР В Р’В Р вЂ™Р’В Р В Р вЂ Р В РІР‚С™Р вЂ™Р’ВР В Р’В Р вЂ™Р’В Р В Р Р‹Р Р†Р вЂљРЎвЂќР В Р’В Р вЂ™Р’В Р В Р Р‹Р РЋРІР‚С”Р В Р’В Р вЂ™Р’В Р В Р Р‹Р Р†РІР‚С›РЎС›Р В Р’В Р вЂ™Р’В Р В РІР‚в„ўР вЂ™Р’В (GM) ===
window.kubokerProcessAction = async function(actionData) {
    if (!game.user.isGM) return;
    let state = foundry.utils.deepClone(canvas.scene.getFlag(FLAG_SCOPE, FLAG_KEY) || { players: {}, center: [], phase: 'join', log: [], currentDC: 15, debugMode: false });
    let changed = false;

