        state.log.unshift(`<div style="background:rgba(255,0,0,0.3); border:1px solid red; padding:5px; border-radius:4px; font-size:11px; color:white; text-align:center;">СЂСџС™РЃ <b>${reporterName}</b> РЎРѓР Т‘Р В°Р В» РЎв‚¬РЎС“Р В»Р ВµРЎР‚Р В° <b>${getParticipantName(t)}</b>!</div>`);
