        for (let id in state.players) { 
            state.players[id].dice = [0,0,0]; state.players[id].isWinner = false; state.players[id].changesLeft = 0; 
            state.players[id].complaints = []; state.players[id].strategy = 'fair'; state.players[id].skill = 'soc'; 
            state.players[id].blackDiceIdx = -1; state.players[id].isConfirmed = false;
