class KubokerGame extends Application {
  static get defaultOptions() { return foundry.utils.mergeObject(super.defaultOptions, { id: "kuboker-window", title: "Р В Р’В Р вЂ™Р’В Р В Р Р‹Р Р†РІР‚С›РЎС›Р В Р’В Р В Р вЂ№Р В Р Р‹Р Р†Р вЂљРЎС™Р В Р’В Р вЂ™Р’В Р В РІР‚в„ўР вЂ™Р’В±Р В Р’В Р вЂ™Р’В Р В Р Р‹Р Р†Р вЂљРЎС›Р В Р’В Р вЂ™Р’В Р В Р Р‹Р Р†Р вЂљРЎСљР В Р’В Р вЂ™Р’В Р В РІР‚в„ўР вЂ™Р’ВµР В Р’В Р В Р вЂ№Р В Р’В Р Р†Р вЂљРЎв„ў", width: 1450, height: 800, resizable: true, dragDrop: [{ dropSelector: "#kuboker-app" }] }); }
  async _renderInner(data) {
    Handlebars.registerHelper('eq', (a, b) => a === b); Handlebars.registerHelper('and', (a, b) => a && b);
    Handlebars.registerHelper('gt', (a, b) => a > b);
    return $(style + Handlebars.compile(template)(data));
  }
  _getState() { return canvas.scene.getFlag(FLAG_SCOPE, FLAG_KEY) || { players: {}, center: [], phase: 'join', log: [], currentDC: 15, debugMode: false }; }

  getData() {
    const state = this._getState(); const playersData = []; const visibleCheatersMap = {}; 
    const centerDice = normalizeDiceValues(state.center).filter((value) => Number.isFinite(value) && value > 0);
    if (state.phase === 'locked' || state.phase === 'reveal') {
        for (let [tId, tData] of Object.entries(state.players)) {
            if (!tData || tData.strategy !== 'cheat') continue;
            visibleCheatersMap[tId] = [];
            for (let [vId, vData] of Object.entries(state.players)) {
                if (!vData || vId === tId || !vData.isParticipating) continue;
                let noticed = false;
                if (tData.degree === 0) noticed = true; 
                else if (tData.degree === 1 && vData.degree > 1) noticed = true; 
                else if (tData.degree === 2 && vData.strategy === 'observe' && vData.degree >= 4) noticed = true; 
                else if (tData.degree === 3 && vData.strategy === 'observe' && vData.degree === 5) noticed = true; 
                if (noticed) visibleCheatersMap[tId].push(vId);
            }
        }
    }
    const sortedIds = Object.keys(state.players).sort((a, b) => Number(isParticipantOwner(state.players[b])) - Number(isParticipantOwner(state.players[a])));
    for (let id of sortedIds) {
        let p = state.players[id];
        if (!p) continue;

        const actor = resolveParticipantActor(p);
        const name = getParticipantName(p, actor);
        const img = getParticipantImage(p, actor);
        const type = getParticipantType(p, actor);
        const dice = normalizeDiceValues(p.dice, [0, 0, 0]).map((value) => value ?? 0);
        const isOwnedByUser = isParticipantOwner(p, actor);
        const isVisualOwner = isOwnedByUser && (!game.user.isGM || type === 'npc' || state.debugMode);
        const canSee = (state.phase === 'reveal') || isVisualOwner;
        const handPresentation = state.phase === 'reveal' ? getHandPresentation(dice, centerDice) : null;
        let exposedTargets = [];

        if (state.phase === 'locked' && isVisualOwner) {
            for (let [cheaterId, observerIds] of Object.entries(visibleCheatersMap)) {
                if (observerIds.includes(id)) {
                    let cheater = state.players[cheaterId];
                    exposedTargets.push({
                        id: cheaterId,
                        name: getParticipantShortName(cheater),
                        alreadyComplained: hasComplaintFrom(cheater, p.id, p.name)
                    });
                }
            }
        }

        playersData.push({
            ...p,
            id,
            name,
            img,
            isActorOwner: isOwnedByUser,
            displayDice: dice.map((d, i) => ({ val: canSee ? d : "?", isHidden: !canSee, isBlack: (p.blackDiceIdx === i), canReroll: (isVisualOwner && state.phase === 'locked' && p.changesLeft > 0 && p.blackDiceIdx !== i) })),
            isVisualOwner,
            mods: getActorMods(actor),
            exposedTargets,
            isCaught: p.complaints?.length > 0,
            handDice: handPresentation?.displayDice || [],
            handResolvedName: handPresentation?.name || p.handName || ""
        });
    }
    return { state, players: playersData, centerDice, isGM: game.user.isGM, isJoinPhase: state.phase === 'join', isDealPhase: state.phase === 'deal', isLockedPhase: state.phase === 'locked', isRevealPhase: state.phase === 'reveal' };
  }

