  activateListeners(html) {
    super.activateListeners(html);
    html.find('.kb-rules-help').click(() => this._showDetailedRules());
    html.find('.kb-join-cb').change(ev => this._sendAction({ action: "toggleJoin", actorId: ev.currentTarget.dataset.actor, isParticipating: ev.currentTarget.checked }));
    html.find('.kb-strat-btn').click(ev => {
