        const p = this._getState().players[actorId];
        if (!p || p.changesLeft <= 0) return;
        $(ev.currentTarget).addClass('rolling'); setTimeout(() => $(ev.currentTarget).removeClass('rolling'), 500);
        if (p.strategy === 'cheat' && p.degree >= 4) {
            new Dialog({ title: "Р В Р’В Р вЂ™Р’В Р В Р’В Р Р†РІР‚С™Р’В¬Р В Р’В Р В Р вЂ№Р В Р’В Р РЋРІР‚СљР В Р’В Р В Р вЂ№Р В Р вЂ Р В РІР‚С™Р РЋРІвЂћСћР В Р’В Р вЂ™Р’В Р В РІР‚в„ўР вЂ™Р’В°Р В Р’В Р вЂ™Р’В Р В Р’В Р Р†Р вЂљР’В¦Р В Р’В Р вЂ™Р’В Р В Р Р‹Р Р†Р вЂљРЎС›Р В Р’В Р вЂ™Р’В Р В Р’В Р Р†Р вЂљР’В Р В Р’В Р вЂ™Р’В Р В Р Р‹Р Р†Р вЂљР’ВР В Р’В Р В Р вЂ№Р В Р вЂ Р В РІР‚С™Р РЋРІвЂћСћР В Р’В Р В Р вЂ№Р В Р’В Р В РІР‚В° Р В Р’В Р вЂ™Р’В Р В Р Р‹Р Р†Р вЂљРІР‚СљР В Р’В Р В Р вЂ№Р В Р’В Р Р†Р вЂљРЎв„ўР В Р’В Р вЂ™Р’В Р В РІР‚в„ўР вЂ™Р’В°Р В Р’В Р вЂ™Р’В Р В Р’В Р Р†Р вЂљР’В¦Р В Р’В Р В Р вЂ№Р В Р’В Р В РІР‚В°", content: `<input type="number" id="die-val" min="1" max="10" value="10" style="width:100%; text-align:center;">`, buttons: { ok: { label: "Р В Р’В Р вЂ™Р’В Р В Р Р‹Р РЋРЎСџР В Р’В Р В Р вЂ№Р В Р’В Р Р†Р вЂљРЎв„ўР В Р’В Р вЂ™Р’В Р В Р Р‹Р Р†Р вЂљР’ВР В Р’В Р вЂ™Р’В Р В Р’В Р Р†Р вЂљР’В¦Р В Р’В Р В Р вЂ№Р В Р’В Р В Р РЏР В Р’В Р В Р вЂ№Р В Р вЂ Р В РІР‚С™Р РЋРІвЂћСћР В Р’В Р В Р вЂ№Р В Р’В Р В РІР‚В°", callback: h => this._sendAction({ action: "dieClick", actorId, dieIndex, newValue: parseInt(h.find('#die-val').val()) }) } } }).render(true);
        } else { this._sendAction({ action: "dieClick", actorId, dieIndex, newValue: Math.floor(Math.random()*10)+1 }); }
    });
    html.find('.kb-disq-btn').click(ev => {
        if ($(ev.currentTarget).hasClass('disabled')) return;
        const targetId = ev.currentTarget.dataset.target;
        const byId = ev.currentTarget.dataset.by;
        const reporter = this._getState().players[byId];
        this._sendAction({ action: "complain", targetId, byId, byName: getParticipantName(reporter) });
    });

    if (game.user.isGM) {
        html.find('#kb-deal').click(async () => {
            let s = this._getState(); s.phase = 'deal'; s.center = [Math.floor(Math.random()*10)+1, Math.floor(Math.random()*10)+1];
            let active = Object.values(s.players).filter(p=>p.isParticipating);
            let maxLvl = active.length > 0 ? Math.max(...active.map(p=>p.level)) : 0;
            s.currentDC = PF2E_DC_BY_LEVEL[maxLvl] || 12;
            s.log.unshift(`<div style="text-align:center; color:#ffd700; border:2px solid #d4af37; background:rgba(212,175,55,0.1); padding:4px; margin-bottom:10px;"><b>Р В Р’В Р вЂ™Р’В Р В Р Р‹Р Р†РІР‚С›РЎС›Р В Р’В Р вЂ™Р’В Р В Р Р‹Р Р†Р вЂљРЎвЂќР В Р’В Р вЂ™Р’В Р В Р Р‹Р РЋРЎв„ў Р В Р’В Р вЂ™Р’В Р В Р Р‹Р РЋРЎв„ўР В Р’В Р вЂ™Р’В Р В Р Р‹Р Р†Р вЂљРІвЂћСћР В Р’В Р вЂ™Р’В Р В РІР‚в„ўР вЂ™Р’В§Р В Р’В Р вЂ™Р’В Р В Р Р‹Р Р†Р вЂљРІвЂћСћР В Р’В Р вЂ™Р’В Р В Р Р‹Р РЋРІР‚С”!</b><br>Р В Р’В Р вЂ™Р’В Р В Р Р‹Р Р†РІР‚С›РЎС›Р В Р’В Р В Р вЂ№Р В Р’В Р Р†Р вЂљРЎв„ўР В Р’В Р В Р вЂ№Р В Р Р‹Р Р†Р вЂљРЎС™Р В Р’В Р вЂ™Р’В Р В Р Р‹Р Р†Р вЂљРІР‚СњР В Р’В Р В Р вЂ№Р В Р’В Р В РІР‚В°Р В Р’В Р вЂ™Р’В Р В РІР‚в„ўР вЂ™Р’Вµ Р В Р’В Р вЂ™Р’В Р В Р Р‹Р Р†Р вЂљРЎС›Р В Р’В Р вЂ™Р’В Р В РІР‚в„ўР вЂ™Р’В±Р В Р’В Р В Р вЂ№Р В Р’В Р Р†Р вЂљР’В°Р В Р’В Р В Р вЂ№Р В Р’В Р В Р РЏР В Р’В Р вЂ™Р’В Р В Р’В Р Р†Р вЂљР’В Р В Р’В Р вЂ™Р’В Р В Р Р‹Р Р†Р вЂљР’ВР В Р’В Р вЂ™Р’В Р В РІР‚в„ўР вЂ™Р’В» Р В Р’В Р вЂ™Р’В Р В Р вЂ Р В РІР‚С™Р вЂ™Р’ВР В Р’В Р вЂ™Р’В Р В РІР‚в„ўР вЂ™Р’В°Р В Р’В Р вЂ™Р’В Р В РІР‚в„ўР вЂ™Р’В·Р В Р’В Р вЂ™Р’В Р В Р Р‹Р Р†Р вЂљРЎС›Р В Р’В Р вЂ™Р’В Р В Р’В Р Р†Р вЂљР’В Р В Р’В Р В Р вЂ№Р В Р вЂ Р В РІР‚С™Р Р†РІР‚С›РІР‚вЂњР В Р’В Р вЂ™Р’В Р В Р вЂ Р Р†Р вЂљРЎвЂєР Р†Р вЂљРІР‚Сљ Р В Р’В Р вЂ™Р’В Р В Р Р‹Р Р†РІР‚С›РЎС›Р В Р’В Р вЂ™Р’В Р В Р’В Р В РІР‚в„–: <b>${s.currentDC}</b></div>`);
            for (let id in s.players) { if(s.players[id].isParticipating) { s.players[id].dice = [Math.floor(Math.random()*10)+1, Math.floor(Math.random()*10)+1, Math.floor(Math.random()*10)+1]; s.players[id].strategy = 'fair'; s.players[id].skill = 'soc'; s.players[id].blackDiceIdx = -1; s.players[id].isConfirmed = false; } }
            await canvas.scene.setFlag(FLAG_SCOPE, FLAG_KEY, s);
        });
        html.find('#kb-lock-run').click(() => this._sendAction({ action: "runLock" }));
        html.find('#kb-reveal').click(async () => {
            let s = this._getState(); s.phase = 'reveal'; let maxS = -1; let winners = [];
            for (let id in s.players) { 
                let p = s.players[id]; if (!p.isParticipating) continue;
                syncParticipantSnapshot(p);
                if (p.complaints?.length > 0) { p.handName = "Р В Р’В Р вЂ™Р’В Р В Р вЂ Р В РІР‚С™Р РЋРЎС™Р В Р’В Р вЂ™Р’В Р В РІР‚в„ўР вЂ™Р’ВР В Р’В Р вЂ™Р’В Р В Р’В Р В РІР‚в„–Р В Р’В Р вЂ™Р’В Р В Р Р‹Р Р†РІР‚С›РЎС›Р В Р’В Р вЂ™Р’В Р В Р вЂ Р В РІР‚С™Р Р†РІР‚С›РЎС›Р В Р’В Р вЂ™Р’В Р В Р Р‹Р Р†Р вЂљРІвЂћСћР В Р’В Р вЂ™Р’В Р В Р вЂ Р В РІР‚С™Р РЋРІР‚СњР В Р’В Р вЂ™Р’В Р В РІР‚в„ўР вЂ™Р’ВР В Р’В Р вЂ™Р’В Р В РІР‚в„ўР вЂ™Р’В¤Р В Р’В Р вЂ™Р’В Р В РІР‚в„ўР вЂ™Р’ВР В Р’В Р вЂ™Р’В Р В Р Р‹Р Р†РІР‚С›РЎС›Р В Р’В Р вЂ™Р’В Р В Р Р‹Р Р†Р вЂљРІвЂћСћР В Р’В Р вЂ™Р’В Р В РІР‚в„ўР вЂ™Р’В¦Р В Р’В Р вЂ™Р’В Р В РІР‚в„ўР вЂ™Р’ВР В Р’В Р вЂ™Р’В Р В Р’В Р Р†Р вЂљР Р‹"; p.score = -1; continue; }
                let res = evaluateHand(p.dice, s.center); p.handName = res.name; p.score = res.score; if (res.score > maxS) maxS = res.score; 
            }
            for (let id in s.players) { s.players[id].isWinner = (s.players[id].isParticipating && s.players[id].score === maxS && maxS !== -1); if (s.players[id].isWinner) winners.push(s.players[id]); }
            const bestHand = winners[0] ? getHandPresentation(winners[0].dice, s.center) : null;
            const comboPreview = bestHand ? renderMiniDiceRow(bestHand.displayDice, "winner-preview") : "";
            let winLog = `<div style="background:linear-gradient(135deg, #1e4d2b, #28a745, #1e4d2b); border:2px solid gold; padding:8px; border-radius:5px; color:white; text-align:center; font-weight:bold; font-size:14px; margin-bottom:10px; box-shadow:0 0 10px black;">РЎР‚РЎСџР РЏРІР‚В  Р В РЎСџР В РЎвЂєР В РІР‚ВР В РІР‚СћР В РІР‚СњР В Р’ВР В РЎС›Р В РІР‚СћР В РІР‚С”Р В Р’В¬: ${winners.map(w=>getParticipantName(w)).join(" Р В РЎвЂ ")}!<br><span style="font-size:11px; color:#ffd700;">Р В РЎв„ўР В РЎвЂўР В РЎВР В Р’В±Р В РЎвЂР В Р вЂ¦Р В Р’В°Р РЋРІР‚В Р В РЎвЂР РЋР РЏ: ${winners[0]?.handName || "Р Р†Р вЂљРІР‚Сњ"}</span>${comboPreview}</div>`;
            s.log.unshift(winLog);
            await canvas.scene.setFlag(FLAG_SCOPE, FLAG_KEY, s);
        });
        html.find('#kb-clear').click(() => this._sendAction({ action: "clear" }));
        html.find('#kb-reset').click(() => this._sendAction({ action: "reset" }));
        html.find('#kb-debug').change(async (ev) => { let s = this._getState(); s.debugMode = ev.currentTarget.checked; await canvas.scene.setFlag(FLAG_SCOPE, FLAG_KEY, s); });
        html.find('.kb-remove-btn').click(ev => { let s = this._getState(); let id = ev.currentTarget.dataset.actor; delete s.players[id]; s.players[`-=${id}`] = null; canvas.scene.setFlag(FLAG_SCOPE, FLAG_KEY, s); });
    }
  }

  async _onDrop(event) {
    if (!game.user.isGM) return;
    const data = JSON.parse(event.dataTransfer.getData('text/plain')); if (data.type !== "Actor") return;
    let actor = await fromUuid(data.uuid); if (!actor) return;
    actor = actor.actor ?? actor;
    let state = this._getState();
    if (!state.players[actor.id]) state.players[actor.id] = { id: actor.id, name: actor.name, img: actor.img, uuid: actor.uuid, actorType: actor.type, level: actor.level || actor.system.details?.level?.value || 0, dice: [0,0,0], strategy: 'fair', skill: 'soc', isParticipating: true, changesLeft: 0, complaints: [], blackDiceIdx: -1, isConfirmed: false };
    else Object.assign(state.players[actor.id], { name: actor.name, img: actor.img, uuid: actor.uuid, actorType: actor.type, level: actor.level || actor.system.details?.level?.value || state.players[actor.id].level || 0 });
    await canvas.scene.setFlag(FLAG_SCOPE, FLAG_KEY, state);
  }

  async _sendAction(data) {
    if (game.user.isGM) await window.kubokerProcessAction(data);
    else await game.user.setFlag(FLAG_SCOPE, FLAG_ACTION, { ...data, ts: Date.now() });
  }
}

if (!window.kubokerHookV130) {
    Hooks.on("updateUser", async (user, changes) => {
        if (!game.user.isGM) return;
        const f = changes.flags?.[FLAG_SCOPE]?.[FLAG_ACTION];
        if (f) { await window.kubokerProcessAction(f); await user.unsetFlag(FLAG_SCOPE, FLAG_ACTION); }
    });
    Hooks.on("updateScene", (scene, data) => {
        if (hasProperty(data, `flags.${FLAG_SCOPE}.${FLAG_KEY}`)) {
            let app = Object.values(ui.windows).find(w => w.id === "kuboker-window");
            if (app) app.render(false);
        }
    });
    window.kubokerHookV130 = true;
}
new KubokerGame().render(true);
})();
